const IMG_MAE = 'data:image/jpeg;base64,';
const IMG_JOOJS = 'data:image/jpeg;base64,';
const IMG_GERAL = 'data:image/jpeg;base64,';

/* ── Petals ── */
const PC = ['#e8265a','#f7a8c4','#d4a853','#f48fb1','#f06292','#e91e63'];
const petalsEl = document.getElementById('petals');
function mkPetal() {
  const p = document.createElement('div'); p.className = 'petal';
  const sz = Math.random()*10+6;
  p.style.cssText = `width:${sz}px;height:${sz}px;left:${Math.random()*100}vw;background:${PC[Math.floor(Math.random()*PC.length)]};animation-duration:${Math.random()*8+6}s;animation-delay:${Math.random()*4}s;border-radius:${Math.random()>.5?'50% 0 50% 0':'50%'};`;
  petalsEl.appendChild(p);
  setTimeout(() => p.remove(), 14000);
}
setInterval(mkPetal, 400);
for (let i=0;i<10;i++) setTimeout(mkPetal, i*150);

// Mensagens e fotos por pessoa
const personData = {
  mamae: {
    emoji: '💗',
    name: 'Mamãe',
    photos: [IMG_MAE, IMG_GERAL],
    gridClass: 'duo',
    message: name => `Feliz Dia Internacional da Mulher, <strong>${name}</strong>! 🌺<br><br>
Tu és a força que me sustenta e sustenta tudo ao seu redor — Ter ti ao nosso lado é um privilégio. faz com que nós tenhamos o suporte que precisamos para seguir em frente.<br><br>
Ser sua família é um presente que não tem preço. Tu transmitiste em nós o amor, a perseverança , a coragem, a empatia e a fé de que tudo é possível. Hoje e sempre, Tu sempre será celebrada, admirada e imensamente amada.<br><br>
<em>Obrigada por ser quem tu és. 💕</em>`
  },
  joojs: {
    emoji: '🌟',
    name: 'Joojs',
    photos: [IMG_JOOJS, IMG_GERAL],
    gridClass: 'duo',
    message: name => `Feliz Dia Internacional das Mulheres, <strong>${name}</strong>! ✨<br><br>
Minhas queridas irmas, tive que fazer junto para nao ter briga, Vossemecês são a luz que ilumina e traz a alegria por onde passam — com as vossas energias boas, distintas, porém que se completam, tornam o mundo um lugar bom de se viver.<br><br>
Espero um dia ser bom o bastante para compensar a vocês tudo aquilo que fizeram por mim.<br><br>
<em>Continuem brilhando que o maninho ama vocês! 💫</em>`
  }
};

function showMessage() {
  const sel = document.getElementById('nameSelect');
  const val = sel.value;
  if (!val) {
    sel.style.borderColor = '#e8265a';
    sel.style.boxShadow = '0 0 0 4px rgba(232,38,90,.2)';
    setTimeout(() => { sel.style.borderColor = ''; sel.style.boxShadow = ''; }, 1200);
    return;
  }

  const data = personData[val];
  document.getElementById('msgEmoji').textContent = data.emoji;
  document.getElementById('msgName').textContent = data.name + ', este momento é seu! 🌸';
  document.getElementById('msgText').innerHTML = data.message(data.name);

  // Build fixed photos
  const photosSection = document.getElementById('msgPhotosSection');
  const photosGrid = document.getElementById('msgPhotosGrid');
  photosGrid.innerHTML = '';
  photosGrid.className = 'msg-photos-grid ' + data.gridClass;

  data.photos.forEach(src => {
    const div = document.createElement('div');
    div.className = 'ph';
    const img = document.createElement('img');
    img.src = src; img.alt = '';
    div.appendChild(img);
    photosGrid.appendChild(div);
  });
  photosSection.style.display = 'block';

  const box = document.getElementById('messageBox');
  box.classList.remove('show'); box.style.display = 'none';
  void box.offsetWidth;
  box.classList.add('show'); box.style.display = 'block';
  launchSparkles();
  setTimeout(() => box.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 80);
}

function launchSparkles() {
  const c = document.getElementById('sparklesContainer'); c.innerHTML = '';
  const sc = ['#d4a853','#e8265a','#f7a8c4','#fff','#f48fb1'];
  for (let i=0;i<24;i++) {
    const s = document.createElement('div'); s.className='spark';
    const tx=(Math.random()-.5)*240, ty=(Math.random()-.5)*240;
    s.style.cssText=`left:${20+Math.random()*60}%;top:${20+Math.random()*60}%;background:${sc[Math.floor(Math.random()*sc.length)]};--tx:${tx}px;--ty:${ty}px;animation-delay:${Math.random()*.4}s;animation-duration:${.8+Math.random()*.8}s;width:${4+Math.random()*6}px;height:${4+Math.random()*6}px;`;
    c.appendChild(s);
  }
}

function copyMsg() {
  const val = document.getElementById('nameSelect').value;
  const data = personData[val] || {};
  const text = document.getElementById('msgText').innerText;
  navigator.clipboard.writeText(`🌸 Feliz Dia Internacional da Mulher, ${data.name}! 🌸\n\n${text}\n\n— 8 de Março 💕`).then(() => {
    const btn = document.querySelector('.share-btn');
    btn.textContent = '✅ Copiado!';
    setTimeout(() => btn.textContent = '📋 Copiar mensagem', 2500);
  });
}

document.getElementById('nameSelect').addEventListener('change', () => {
  const box = document.getElementById('messageBox');
  if (box.style.display !== 'none') showMessage();
});
